{
  "name": "Fizika: Arkhimédész és a Víz",
  "description": "Interaktív oktatóprogram a hidrosztatikai nyomásról és Arkhimédész törvényéről szimulációkkal és játékkal."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ViewState = 'simulation' | 'game';

export interface Question {
  id: number;
  text: string;
  options: string[];
  correctIndex: number;
  explanation: string;
}

export interface SimulationConfig {
  objectMass: number;    // kg
  objectVolume: number;  // m^3 (simplified unit for UI)
  liquidDensity: number; // kg/m^3
}

export interface GameEntity {
  id: number;
  type: 'goldfish' | 'shark' | 'bubble';
  x: number;
  y: number;
  speed: number;
  scale: number;
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'danger' | 'success';
}

export const Button: React.FC<ButtonProps> = ({ children, className = '', variant = 'primary', ...props }) => {
  let baseStyles = "px-6 py-2 rounded-full font-semibold transition-all duration-300 transform hover:scale-105 active:scale-95 shadow-lg border backdrop-blur-md ";

  const variants = {
    primary: "bg-white/20 border-white/40 text-white hover:bg-white/30",
    danger: "bg-red-500/40 border-red-400/50 text-white hover:bg-red-500/60",
    success: "bg-green-500/40 border-green-400/50 text-white hover:bg-green-500/60"
  };

  return (
    <button className={`${baseStyles} ${variants[variant]} ${className}`} {...props}>
      {children}
    </button>
  );
};

import React, { useState } from 'react';
import { Check, X } from 'lucide-react';
import { Question } from '../types';
import { Button } from './Button';

interface QuizProps {
  questions: Question[];
  onScoreUpdate: (points: number) => void;
}

export const Quiz: React.FC<QuizProps> = ({ questions, onScoreUpdate }) => {
  const [answeredState, setAnsweredState] = useState<Record<number, 'correct' | 'incorrect' | null>>({});

  const handleAnswer = (questionId: number, selectedIndex: number, correctIndex: number) => {
    if (answeredState[questionId]) return; // Already answered

    const isCorrect = selectedIndex === correctIndex;
    setAnsweredState(prev => ({ ...prev, [questionId]: isCorrect ? 'correct' : 'incorrect' }));

    onScoreUpdate(isCorrect ? 1 : -1);
  };

  return (
    <div className="space-y-6 mt-8">
      <h3 className="text-2xl font-bold mb-4 text-white drop-shadow-md">Tudáspróba</h3>
      {questions.map((q) => (
        <div key={q.id} className="glass-panel p-6 rounded-2xl relative overflow-hidden transition-all duration-500">
          <div className="relative z-10">
            <p className="text-lg font-medium mb-4">{q.text}</p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {q.options.map((option, idx) => {
                const isAnswered = answeredState[q.id] !== undefined;
                const isCorrectOption = idx === q.correctIndex;
                const isSelectedAndWrong = answeredState[q.id] === 'incorrect' && !isCorrectOption; 
                // Note: We don't track exactly which wrong answer was clicked for simplicity in this view, 
                // but showing the correct one after answering is good practice.

                let btnClass = "text-left p-3 rounded-xl border border-white/20 transition-colors hover:bg-white/10";

                if (answeredState[q.id] === 'correct' && isCorrectOption) {
                  btnClass = "text-left p-3 rounded-xl border border-green-400 bg-green-500/30";
                } else if (answeredState[q.id] === 'incorrect' && isCorrectOption) {
                    btnClass = "text-left p-3 rounded-xl border border-green-400 bg-green-500/30 opacity-70";
                } else if (answeredState[q.id] === 'incorrect' && !isCorrectOption) {
                   // Ideally we'd highlight the specifically clicked wrong answer, but here we just show state
                   btnClass = "text-left p-3 rounded-xl border border-red-400 bg-red-500/20 opacity-50";
                }

                return (
                  <button
                    key={idx}
                    disabled={isAnswered}
                    onClick={() => handleAnswer(q.id, idx, q.correctIndex)}
                    className={btnClass}
                  >
                    {option}
                  </button>
                );
              })}
            </div>

            {answeredState[q.id] && (
              <div className={`mt-4 p-3 rounded-lg flex items-center gap-3 animate-in fade-in slide-in-from-top-2 duration-300 ${answeredState[q.id] === 'correct' ? 'bg-green-500/20 text-green-100' : 'bg-red-500/20 text-red-100'}`}>
                {answeredState[q.id] === 'correct' ? <Check className="w-6 h-6" /> : <X className="w-6 h-6" />}
                <span>{answeredState[q.id] === 'correct' ? 'Helyes válasz!' : 'Sajnos nem jó.'} {q.explanation}</span>
              </div>
            )}
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ArrowDown, ArrowUp } from 'lucide-react';

export const BuoyancySimulation: React.FC = () => {
  // Physical constants
  // Mass in kg, Volume in arbitrary units (let's say 1 unit = 0.001 m^3 = 1 Liter for simplicity visually)
  // Liquid Density in kg/unit
  const [mass, setMass] = useState(1.0); 
  const [volume, setVolume] = useState(1.0); // 1.0 means density of body = mass if mass is 1.0
  const [liquidDensity, setLiquidDensity] = useState(1.0); // Water approx

  // Calculate physics state
  const bodyDensity = mass / volume;
  const isFloating = bodyDensity < liquidDensity;
  const isNeutral = Math.abs(bodyDensity - liquidDensity) < 0.01;
  const isSinking = bodyDensity > liquidDensity;

  // Determine submerged percentage (clamped 0 to 1)
  // If floating: V_sub = (rho_body / rho_liquid) * V_total
  let submergedRatio = 1.0;
  if (isFloating) {
    submergedRatio = bodyDensity / liquidDensity;
  }

  // Visual position (0% = top of liquid, 100% = bottom of container)
  // We simulate the equilibrium position
  const [visualY, setVisualY] = useState(50); // percentage from top of container

  useEffect(() => {
    let targetY = 100; // Bottom
    if (isFloating) {
      // If floating, it sits at the surface level, submerged by ratio
      // Visual tweak: 0 is top of water. The object center is at 0 + height/2 - submergedHeight.
      // Let's simplify: 20% is surface level. 80% is bottom.
      targetY = 20; 
    } else if (isNeutral) {
      targetY = 50; // Middle
    } else {
      targetY = 85; // Bottom
    }
    setVisualY(targetY);
  }, [isFloating, isNeutral, submergedRatio]);

  // Forces calculation for display
  const gravityForce = (mass * 9.81).toFixed(1);
  const buoyancyForce = (Math.min(1, liquidDensity / bodyDensity) * mass * 9.81).toFixed(1); // Approximate for display when sinking vs floating

  // Real formula: F_buoy = rho_liquid * V_submerged * g
  // If floating, F_buoy = F_grav. If sinking, F_buoy = rho_liquid * V_total * g
  const actualBuoyancy = (isSinking ? (liquidDensity * volume * 9.81) : (mass * 9.81)).toFixed(2);


  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      {/* Controls */}
      <div className="glass-panel p-6 rounded-2xl space-y-6">
        <h3 className="text-xl font-bold border-b border-white/20 pb-2">Kísérleti beállítások</h3>

        <div className="space-y-2">
          <label className="flex justify-between text-sm font-medium">
            <span>Test tömege (m)</span>
            <span>{mass.toFixed(1)} kg</span>
          </label>
          <input 
            type="range" min="0.1" max="5.0" step="0.1" 
            value={mass} onChange={(e) => setMass(parseFloat(e.target.value))}
            className="w-full h-2 bg-white/20 rounded-lg appearance-none cursor-pointer accent-blue-400"
          />
        </div>

        <div className="space-y-2">
          <label className="flex justify-between text-sm font-medium">
            <span>Test térfogata (V)</span>
            <span>{volume.toFixed(1)} L</span>
          </label>
          <input 
            type="range" min="0.5" max="3.0" step="0.1" 
            value={volume} onChange={(e) => setVolume(parseFloat(e.target.value))}
            className="w-full h-2 bg-white/20 rounded-lg appearance-none cursor-pointer accent-blue-400"
          />
        </div>

        <div className="space-y-2">
          <label className="flex justify-between text-sm font-medium">
            <span>Folyadék sűrűsége (ρ)</span>
            <span>{liquidDensity.toFixed(1)} kg/L</span>
          </label>
          <input 
            type="range" min="0.5" max="2.0" step="0.1" 
            value={liquidDensity} onChange={(e) => setLiquidDensity(parseFloat(e.target.value))}
            className="w-full h-2 bg-white/20 rounded-lg appearance-none cursor-pointer accent-cyan-400"
          />
        </div>

        <div className="mt-4 p-4 bg-black/20 rounded-xl text-sm space-y-1">
          <p>Test sűrűsége: <span className="font-bold text-yellow-300">{(mass/volume).toFixed(2)} kg/L</span></p>
          <p>Állapot: <span className="font-bold text-white">
            {isFloating ? 'ÚSZIK (Részben kiemelkedik)' : isNeutral ? 'LEBEG (Bárhol megáll)' : 'ELMERÜL (Lesüllyed)'}
          </span></p>
        </div>
      </div>

      {/* Visualizer */}
      <div className="glass-panel p-8 rounded-2xl flex flex-col items-center justify-center relative min-h-[400px]">
        {/* Beaker */}
        <div className="relative w-64 h-80 border-b-4 border-x-4 border-white/30 rounded-b-3xl overflow-hidden backdrop-blur-sm bg-white/5">

          {/* Water */}
          <div className="absolute bottom-0 left-0 right-0 bg-cyan-500/40 transition-all duration-1000 ease-in-out border-t border-cyan-300/50"
               style={{ height: '80%' }}>
             <div className="absolute top-0 left-0 w-full h-2 bg-white/20 animate-pulse"></div>
             {/* Bubbles */}
             <div className="bubble w-2 h-2 left-[10%]" style={{animationDuration: '4s'}}></div>
             <div className="bubble w-3 h-3 left-[30%]" style={{animationDuration: '6s', animationDelay: '1s'}}></div>
             <div className="bubble w-1 h-1 left-[70%]" style={{animationDuration: '3s', animationDelay: '2s'}}></div>
          </div>

          {/* Object */}
          <div 
            className="absolute left-1/2 transform -translate-x-1/2 transition-all duration-1000 ease-[cubic-bezier(0.34,1.56,0.64,1)] flex items-center justify-center shadow-xl border border-white/40"
            style={{ 
              top: `${visualY}%`, 
              width: `${Math.sqrt(volume) * 50}px`, 
              height: `${Math.sqrt(volume) * 50}px`,
              background: 'linear-gradient(145deg, #fbbf24, #d97706)',
              borderRadius: '8px'
            }}
          >
             <span className="text-xs font-bold text-black/60">m={mass}</span>

             {/* Vectors */}
             <div className="absolute -top-12 left-1/2 -translate-x-1/2 flex flex-col items-center">
                <span className="text-[10px] text-cyan-200 mb-1">Ffel={actualBuoyancy}N</span>
                <ArrowUp className="text-cyan-300" size={24} strokeWidth={3} />
             </div>
             <div className="absolute -bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center">
                <ArrowDown className="text-red-300" size={24} strokeWidth={3} />
                <span className="text-[10px] text-red-200 mt-1">Fg={gravityForce}N</span>
             </div>
          </div>

        </div>
        <p className="mt-4 text-sm text-white/70 italic">Szimulált üvegkád víz</p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';

export const PressureSimulation: React.FC = () => {
  const [depth, setDepth] = useState(10); // meters
  const density = 1000; // water kg/m3
  const g = 9.81;

  // p = rho * g * h
  // Result in Pascal, convert to atm approx (1 atm = 101325 Pa)
  const pressurePa = density * g * depth;
  const pressureAtm = (pressurePa / 101325).toFixed(2);
  const totalPressure = (parseFloat(pressureAtm) + 1).toFixed(2); // Adding 1 atm atmospheric

  return (
    <div className="glass-panel p-6 rounded-2xl mt-8">
      <h3 className="text-xl font-bold mb-4">Hidrosztatikai nyomás szimuláció</h3>
      <div className="flex flex-col md:flex-row gap-8 items-center">

        <div className="flex-1 w-full space-y-4">
          <div className="space-y-2">
            <label className="flex justify-between">
              <span>Mélység (h)</span>
              <span>{depth} m</span>
            </label>
            <input 
              type="range" min="0" max="100" step="1"
              value={depth} onChange={(e) => setDepth(parseInt(e.target.value))}
              className="w-full h-2 bg-white/20 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
          </div>
          <div className="bg-black/20 p-4 rounded-lg text-sm">
             <p>Képlet: <code className="text-yellow-300">p = ρ · g · h</code></p>
             <p className="mt-2">Víznyomás: <span className="font-bold">{pressureAtm} atm</span></p>
             <p>Abszolút nyomás (+légköri): <span className="font-bold text-green-300">{totalPressure} atm</span></p>
          </div>
        </div>

        <div className="w-24 h-64 bg-gradient-to-b from-cyan-300 to-blue-900 rounded-lg relative border border-white/30 shadow-inner">
           {/* Depth Marker */}
           <div 
             className="absolute w-full border-t-2 border-dashed border-white flex items-center"
             style={{ top: `${depth}%` }}
           >
             <span className="absolute -right-20 bg-white/10 px-2 py-1 rounded text-xs">{depth}m</span>
           </div>

           {/* Diver icon */}
           <div 
              className="absolute left-1/2 -translate-x-1/2 transition-all duration-300"
              style={{ top: `${depth}%`, transform: 'translate(-50%, -50%)' }}
           >
             <div className="w-8 h-8 bg-orange-500 rounded-full border-2 border-white shadow-lg flex items-center justify-center text-[10px] font-bold">
               P
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { GameEntity } from '../types';
import { Button } from './Button';
import { Trophy, RefreshCw } from 'lucide-react';

interface SubmarineGameProps {
  onScoreUpdate: (points: number) => void;
  totalScore: number;
}

export const SubmarineGame: React.FC<SubmarineGameProps> = ({ onScoreUpdate, totalScore }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [gameOver, setGameOver] = useState(false);

  // Game State Refs (for loop performance)
  const submarineRef = useRef({ y: 200, velocity: 0, density: 1.0 }); // density 1.0 = neutral
  const entitiesRef = useRef<GameEntity[]>([]);
  const scoreRef = useRef(0);
  const frameRef = useRef(0);
  const lastTimeRef = useRef(0);

  // Constants
  const GRAVITY = 0.15;
  const WATER_DENSITY = 1.0;
  const LIFT_FACTOR = 0.25; // Sensitivity of density control
  const GAME_SPEED = 3;

  const [densityControl, setDensityControl] = useState(1.0); // UI State for slider

  const startGame = () => {
    setIsPlaying(true);
    setGameOver(false);
    submarineRef.current = { y: 200, velocity: 0, density: 1.0 };
    entitiesRef.current = [];
    scoreRef.current = 0;
    setDensityControl(1.0);
    lastTimeRef.current = performance.now();
  };

  const handleDensityChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    setDensityControl(val);
    submarineRef.current.density = val;
  };

  useEffect(() => {
    if (!isPlaying || gameOver) return;

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const animate = (time: number) => {
      if (!isPlaying || gameOver) return;

      const deltaTime = time - lastTimeRef.current;
      lastTimeRef.current = time;

      // Clear Canvas
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw Background (Sea)
      const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
      gradient.addColorStop(0, '#60a5fa');
      gradient.addColorStop(1, '#1e3a8a');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw Seabed
      ctx.fillStyle = '#0f172a';
      ctx.beginPath();
      ctx.moveTo(0, canvas.height);
      for(let i=0; i<=canvas.width; i+=50) {
        ctx.lineTo(i, canvas.height - 30 + Math.sin(i/100 + time/1000)*10);
      }
      ctx.lineTo(canvas.width, canvas.height);
      ctx.fill();

      // --- Physics ---
      const sub = submarineRef.current;

      // F_net = F_buoy - F_gravity
      // Modeling simplified: Accel = (DensityWater - DensitySub) * Factor
      // If DensitySub < Water(1.0), Accel is Negative (Up)
      // If DensitySub > Water(1.0), Accel is Positive (Down)
      const acceleration = (sub.density - WATER_DENSITY) * LIFT_FACTOR;

      sub.velocity += acceleration;
      sub.velocity *= 0.98; // Drag
      sub.y += sub.velocity;

      // Boundaries
      if (sub.y < 30) { sub.y = 30; sub.velocity = 0; }
      if (sub.y > canvas.height - 60) { sub.y = canvas.height - 60; sub.velocity = 0; }

      // --- Entities ---
      // Spawn logic
      if (Math.random() < 0.02) {
        const type = Math.random() > 0.3 ? 'goldfish' : 'shark';
        entitiesRef.current.push({
          id: Date.now() + Math.random(),
          type,
          x: canvas.width + 50,
          y: Math.random() * (canvas.height - 100) + 50,
          speed: GAME_SPEED + Math.random(),
          scale: 0.8 + Math.random() * 0.4
        });
      }
      // Bubbles
      if (Math.random() < 0.05) {
         entitiesRef.current.push({
          id: Date.now() + Math.random(),
          type: 'bubble',
          x: canvas.width + 50,
          y: Math.random() * canvas.height,
          speed: GAME_SPEED * 1.5,
          scale: 0.2 + Math.random() * 0.3
        });
      }

      // Update and Draw Entities
      entitiesRef.current.forEach((entity, index) => {
        entity.x -= entity.speed;

        // Draw Entity
        ctx.save();
        ctx.translate(entity.x, entity.y);
        ctx.scale(entity.scale, entity.scale); // Flip if needed, but they come from right
        ctx.scale(-1, 1); // Face left

        if (entity.type === 'goldfish') {
          ctx.fillStyle = '#fbbf24';
          ctx.beginPath();
          ctx.ellipse(0, 0, 15, 8, 0, 0, Math.PI * 2);
          ctx.fill();
          ctx.beginPath(); // Tail
          ctx.moveTo(10, 0); ctx.lineTo(20, -8); ctx.lineTo(20, 8); ctx.fill();
        } else if (entity.type === 'shark') {
          ctx.fillStyle = '#94a3b8';
          ctx.beginPath();
          ctx.ellipse(0, 0, 25, 12, 0, 0, Math.PI * 2);
          ctx.fill();
          ctx.fillStyle = '#fff'; // Eye
          ctx.beginPath(); ctx.arc(-10, -5, 2, 0, Math.PI*2); ctx.fill();
          ctx.fillStyle = '#ef4444'; // Fin
          ctx.beginPath(); ctx.moveTo(0, -12); ctx.lineTo(10, -25); ctx.lineTo(15, -10); ctx.fill();
        } else {
          // Bubble
          ctx.strokeStyle = 'rgba(255,255,255,0.4)';
          ctx.lineWidth = 2;
          ctx.beginPath(); ctx.arc(0,0, 10, 0, Math.PI*2); ctx.stroke();
        }
        ctx.restore();

        // Collision
        const dx = entity.x - 100; // Sub X is fixed roughly at 100 visually
        const dy = entity.y - sub.y;
        const dist = Math.sqrt(dx*dx + dy*dy);

        // Simple circle collision
        if (entity.type !== 'bubble' && dist < 40) {
           if (entity.type === 'goldfish') {
             onScoreUpdate(1);
             entitiesRef.current.splice(index, 1);
           } else {
             // Hit shark
             setGameOver(true);
             setIsPlaying(false);
           }
        }
      });

      // Cleanup off-screen
      entitiesRef.current = entitiesRef.current.filter(e => e.x > -50);

      // --- Draw Submarine ---
      ctx.save();
      ctx.translate(100, sub.y);
      // Hull
      ctx.fillStyle = '#f59e0b'; // Yellow Sub
      ctx.beginPath();
      ctx.roundRect(-40, -15, 80, 30, 15);
      ctx.fill();
      ctx.strokeStyle = '#78350f';
      ctx.lineWidth = 2;
      ctx.stroke();
      // Tower
      ctx.fillStyle = '#f59e0b';
      ctx.fillRect(-10, -30, 20, 15);
      ctx.strokeRect(-10, -30, 20, 15);
      // Periscope
      ctx.beginPath(); ctx.moveTo(0, -30); ctx.lineTo(0, -40); ctx.lineTo(10, -40); ctx.stroke();
      // Windows
      ctx.fillStyle = '#60a5fa';
      ctx.beginPath(); ctx.arc(-20, 0, 5, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(0, 0, 5, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(20, 0, 5, 0, Math.PI*2); ctx.fill();
      // Propeller
      ctx.fillStyle = '#9ca3af';
      ctx.fillRect(-45, -5, 5, 10);

      ctx.restore();

      frameRef.current = requestAnimationFrame(animate);
    };

    frameRef.current = requestAnimationFrame(animate);

    return () => cancelAnimationFrame(frameRef.current);
  }, [isPlaying, gameOver, onScoreUpdate]);

  return (
    <div className="flex flex-col md:flex-row gap-6 h-full items-stretch">
       {/* Game Area */}
       <div className="flex-1 relative glass-panel rounded-2xl overflow-hidden shadow-2xl">
          <canvas 
            ref={canvasRef} 
            width={800} 
            height={500} 
            className="w-full h-full object-cover bg-blue-900"
          />

          {/* Overlay UI */}
          <div className="absolute top-4 left-4 text-white text-shadow-md">
            <h3 className="text-xl font-bold">Pontszám: {totalScore}</h3>
          </div>

          {(!isPlaying || gameOver) && (
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center text-center p-6">
              <h2 className="text-4xl font-bold mb-4 text-yellow-400">
                {gameOver ? 'Játék Vége!' : 'Tengeralattjáró Kaland'}
              </h2>
              <p className="mb-8 max-w-md text-lg">
                Irányítsd a tengeralattjáró sűrűségét! <br/>
                <span className="text-sm text-gray-300">
                  Kisebb sűrűség = Felhajtóerő (Emelkedés) <br/>
                  Nagyobb sűrűség = Süllyedés
                </span>
              </p>
              <Button onClick={startGame} className="flex items-center gap-2 text-xl px-8 py-3">
                 {gameOver ? <RefreshCw/> : <Trophy />}
                 {gameOver ? 'Újra' : 'Indítás'}
              </Button>
            </div>
          )}
       </div>

       {/* Controls */}
       <div className="w-full md:w-32 glass-panel p-4 rounded-2xl flex flex-col items-center justify-center relative">
          <div className="absolute top-4 text-sm font-bold text-center w-full">Sűrűség</div>

          <div className="h-64 flex items-center relative py-4">
             {/* Gradient bar representing density */}
             <div className="absolute left-1/2 -translate-x-1/2 w-4 h-full rounded-full bg-gradient-to-t from-blue-900 via-blue-500 to-cyan-200 opacity-50"></div>

             <input 
              type="range" 
              orient="vertical"
              min="0.5" max="1.5" step="0.01"
              value={densityControl}
              onChange={handleDensityChange}
              className="appearance-none h-full w-12 bg-transparent z-10 cursor-pointer density-slider"
              style={{ writingMode: 'bt-lr', WebkitAppearance: 'slider-vertical' } as any}
             />
          </div>

          <div className="mt-4 text-center">
             <div className="text-2xl font-bold">{densityControl.toFixed(2)}</div>
             <div className="text-xs text-gray-300">kg/L</div>
             <div className="mt-2 text-xs">
               {densityControl < 1 ? 'Emelkedés' : densityControl > 1 ? 'Süllyedés' : 'Lebegés'}
             </div>
          </div>
       </div>
    </div>
  );
};
